"""matplotlib.image — image handling stubs."""

import numpy as _np


class AxesImage:
    """Stub AxesImage."""

    def __init__(self, ax, **kwargs):
        self._data = None
        self._cmap = kwargs.get('cmap', 'viridis')
        self._norm = kwargs.get('norm', None)
        self._extent = kwargs.get('extent', None)

    def set_data(self, A):
        self._data = A

    def get_array(self):
        return self._data

    def set_clim(self, vmin=None, vmax=None):
        pass

    def get_clim(self):
        return (0, 1)

    def set_cmap(self, cmap):
        self._cmap = cmap

    def get_cmap(self):
        return self._cmap

    def set_extent(self, extent):
        self._extent = extent

    def get_extent(self):
        return self._extent


